function create2026VideoFolders() {
  // --- CONFIGURATION ---

  // 1. The specific folder where these projects belong
  //    (The script will search your whole Drive for this name)
  var destinationFolderName = "2026 Videos"; 

  // 2. The sub-folders you want inside every single video project
  var subFolderNames = [
    "01 Raw Footage",
    "02 B-Roll",
    "03 Images",
    "04 Final Video",
    "05 Transcript",
    "06 Shorts and Reels"
  ];

  // --- THE WORK ---
  var drive = DriveApp;
  var parentFolder;

  // 1. Find the "2026 Videos" folder
  var folders = drive.getFoldersByName(destinationFolderName);

  if (folders.hasNext()) {
    parentFolder = folders.next();
  } else {
    // Stop if we can't find it
    Logger.log("Error: I could not find the folder '" + destinationFolderName + "'. Please create it first!");
    return;
  }

  // 2. Loop from 1 to 20 to create the folders
  for (var i = 1; i <= 20; i++) {

    // This creates the name "X1 Video Title", "X2 Video Title", etc.
    var currentProjectName = "X" + i + " Video Title";

    // Create the main project folder
    var projectFolder = parentFolder.createFolder(currentProjectName);

    // Create the sub-folders inside it
    subFolderNames.forEach(function(subName) {
      projectFolder.createFolder(subName);
    });
  }
}
